@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<span class="badge bg-primary fs-6 mb-3 d-inline-block">
    @_notifications.Count notification@(_notifications.Count == 1 ? "" : "s")
</span>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    protected override void OnInitialized()
    {
        // Load initial data during prerender AND on interactive init.
        // On the interactive init this reuses in-memory state — no extra fetch.
        _notifications = NotificationService.GetAll();
        _lastCheck = DateTime.UtcNow;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires in an interactive context, never during
            // static SSR prerender — so the polling loop starts only when live.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(5));

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate new notifications arriving server-side
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetNewSince(_lastCheck);
            if (newer.Count > 0)
            {
                _lastCheck = DateTime.UtcNow;
                _notifications = NotificationService.GetAll();
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

